head.script:
/*세관 반출신고 등록 */

//Date
scwin.strFromDate = $c.date.getServerDateTime("yyyyMMdd").substring(0, 8);   // 현재년월일을 구한다.
scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");                    // 현재년월일을 구한다.
scwin.strDate = scwin.strFromDate + scwin.strToDate;

// 세션정보 가져오기
scwin.userId = $c.data.getMemInfo("userId") == null ? "" : $c.data.getMemInfo("userId");
scwin.lobranCd = $c.data.getMemInfo("lobranCd") == null ? "" : $c.data.getMemInfo("lobranCd");

scwin.initCnt = 0;
scwin.isOpenRetrieve = false;

scwin.onpageload = function () {
    divsCrryinoutYn.hide();
    chb_printCheck.setValue(1);
    chb_previewCheck.setValue(1);

    const codeOptions = [
        { grpCd: "OP135", compID: "gr_retrieve:divsCrryinoutClsCd", opt: { "range": "1" } },
        { grpCd: "OP136", compID: "gr_retrieve:crryoutTermExtdCls", opt: { "range": "1" } },
        { grpCd: "OP498", compID: "gr_retrieve:xrayClsCd", opt: { "range": "1" } },
        { grpCd: "SD116", compID: "gr_retrieve:crryinPackKnd", opt: { "range": "1" } },
    ];

    $c.data.setCommonCode(codeOptions, scwin.onLoadCommonCode);

    $c.gus.cfDisableBtn([btn_save, btn_delete]);
    $c.gus.cfDisableObjects([tb_retrieveData]);
    scwin.chkInit();
};

scwin.onUdcCompleted = function () {
    scwin.chkInit();
};

scwin.onLoadCommonCode = function () {
    scwin.chkInit();
};

scwin.chkInit = function () {
    if (++scwin.initCnt >= 3) {
        scwin.init();
    }
};

scwin.init = function () {
    let params = $c.data.getParameter();
    if ("" != params?.odrNo && "1" == params?.openFlag) { //다른 페이지에서 넘어왔을 때
        scwin.f_OpenRetrieve();
    } else {
        //점소가 인천지사이면서 김은순씨 아이디로 들어왔을 경우 분할반출체크박스가 보이도록 변경
        if ((scwin.lobranCd == "4AA" && scwin.userId == "940904") || scwin.userId == "pchang" || scwin.userId == "seokjy") {
            divsCrryinoutYn.show();
        }
    }
};

//-------------------------------------------------------------------------
// 세관반출입현황에서 조회
//-------------------------------------------------------------------------
scwin.f_OpenRetrieve = async function () {
    let params = $c.data.getParameter();
    let cfsCls = params?.cfsCls ?? "";
    let wrkPlCd = params?.wrkPlCd ?? "";
    let wrkPlNm = params?.wrkPlNm ?? "";
    let mrn = params?.mrn ?? "";
    let msn = params?.msn ?? "";
    let hsn = params?.hsn ?? "";
    let blNo = params?.blNo ?? "";
    let odrNo = params?.odrNo ?? "";
    let cntrBulk = params?.cntrBulk ?? "";

    ed_wrkPlCd.setValue(wrkPlCd);
    ed_wrkPlNm.setValue(wrkPlNm);
    ed_mrn.setValue(mrn);
    ed_msn.setValue(msn);
    ed_hsn.setValue(hsn);
    ed_blNo.setValue(blNo);
    ed_odrNo.setValue(odrNo);

    if (cfsCls == "") {
        preRetrieve.setValue("1");
    } else {
        preRetrieve.setValue("0");
    }

    let flag = 0;
    for (let i = 0; i < ds_retrieve.getRowCount(); i++) {
        if (ds_retrieve.getCellData(row, "crryinoutDeclarNo") == "1") {
            flag++;
        }
    }
    if (flag > 1) {
        await $c.win.alert("1회에 1건만 처리할 수 있습니다.");
        return false;
    }

    dma_condition.set("wrkPlCd", wrkPlCd);
    dma_condition.set("mrn", mrn);
    dma_condition.set("msn", ed_msn.getValue() == "" ? -1 : ed_msn.getValue());
    dma_condition.set("hsn", ed_hsn.getValue() == "" ? -1 : ed_hsn.getValue());
    dma_condition.set("blNo", blNo);
    dma_condition.set("odrNo", odrNo);
    dma_condition.set("cntrBulk", cntrBulk);

    if (cfsCls == "") {
        dma_condition.set("preRetrieve", "1");
    } else {
        dma_condition.set("preRetrieve", "0");
    }

    scwin.isOpenRetrieve = true;
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 조회
//------------------------------------------------------------------------- 
scwin.f_Retrieve = async function () {
    let chkwrkplcd = ed_wrkPlCd.getValue();
    if ($c.gus.cfIsNull(chkwrkplcd)) {
        await $c.win.alert("작업장 코드는 필수 입력 항목입니다.");
        ed_wrkPlCd.focus();
        return;
    }

    let chk = await $c.gus.cfValidate([tb_queryList], null, true);
    // 필수항목 체크
    if (!chk) {
        return;
    }

    if (ed_mrn.getValue() == "" && ed_blNo.getValue() == "" && ed_odrNo.getValue() == "" && crryinoutDtmFrom.getValue() == "") {
        await $c.win.alert("MRN,BL번호,오더번호,일자 중 하나는 입력해야 합니다.");
        return;
    } else {
        if (ed_mrn.getValue() != "") {
            if (ed_mrn.getValue().length < 11) {
                await $c.win.alert("MRN은 11자리입니다");
                ed_mrn.focus();
                return;
            }
        }
    }

    if (ed_odrNo.getValue() != "") {
        if (ed_odrNo.getValue().length < 13) {
            await $c.win.alert("오더번호는 13자리입니다.");
            ed_odrNo.focus();
            return;
        }
    }

    if (!$c.gus.cfIsAfterDate(crryinoutDtmFrom.getValue(), crryinoutDtmTo.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        crryinoutDtmFrom.focus();
        return;
    }

    let cheVal = "0";
    if (preRetrieve.getValue() == "1") {
        cheVal = "1";
    }

    dma_condition.set("wrkPlCd", ed_wrkPlCd.getValue());
    dma_condition.set("mrn", ed_mrn.getValue());
    dma_condition.set("msn", ed_msn.getValue() == "" ? -1 : ed_msn.getValue());
    dma_condition.set("hsn", ed_hsn.getValue() == "" ? -1 : ed_hsn.getValue());
    dma_condition.set("blNo", ed_blNo.getValue());
    dma_condition.set("odrNo", ed_odrNo.getValue());
    dma_condition.set("preRetrieve", "0");
    dma_condition.set("crryinoutDtmFrom", crryinoutDtmFrom.getValue());
    dma_condition.set("crryinoutDtmTo", crryinoutDtmTo.getValue());

    //분할반출
    if (divsCrryinoutYn.getValue() == "1") {
        dma_condition.set("divsCrryinoutYn", "1");
    } else {
        dma_condition.set("divsCrryinoutYn", "0");
    }
    $c.sbm.execute(sbm_retrieve);
};

//전송
scwin.f_Save_0 = async function (val) {
    let k = 0;
    let sndClsCd = "0";

    //변경한 데이터가 있는지 체크한다. 
    if (ds_retrieve.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    // 필수항목 체크
    if (!await $c.gus.cfValidate([gr_retrieve], null, true)) {
        return;
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {
        for (i = 0; i < ds_retrieve.getRowCount(); i++) {
            if (ds_retrieve.getRowStatusValue(i) == 1) { //갱신
                if (ds_retrieve.getCellData(i, "che") == 1) {
                    k++;
                    if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "55" || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "70"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "82" || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "90") {
                        if (ds_retrieve.getCellData(i, "crryinoutBasisNo") != "") {
                            await $c.win.alert("현재 선택하신 반출유형은 반출근거번호가 필요없습니다.삭제해 주시길 바랍니다.");
                            gr_retrieve.setFocusedCell(i, "crryinoutBasisNo", true);
                            return;
                        }
                    } else {
                        if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "") {
                            await $c.win.alert("반출유형코드는 필수항목입니다");
                            gr_retrieve.setFocusedCell(i, "crryinoutPatternCd", true);
                            return;
                        }
                    }

                    sndClsCd = "0"; // 전송구분코드

                    ds_retrieve.setCellData(i, "sndClsCd", sndClsCd);
                }
            } else if (ds_retrieve.getRowStatusValue(i) == 3) { //삭제
                if (ds_retrieve.getCellData(i, "che") == 1) k++;
            }
        }
        if (k == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["항목"]);
            return;
        }

        $c.sbm.execute(sbm_save);
    }
};

scwin.getValItem = function (id, name, options = {}) {
    return {
        id: id,
        name: name,
        mandatory: (options.mandatory !== undefined) ? options.mandatory : true,
        ...options
    };
};

//저장
scwin.f_Save_3 = async function (val) {
    let k = 0;
    let sndClsCd = "0";

    //변경한 데이터가 있는지 체크한다. 
    if (ds_retrieve.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    if (!await $c.gus.cfValidate([gr_retrieve], null, true)) {
        return false;
    }

    if (await $c.win.confirm("저장하시겠습니까?")) {
        for (i = 0; i < ds_retrieve.getRowCount(); i++) {
            if (ds_retrieve.getRowStatusValue(i) == 1) { //갱신
                if (ds_retrieve.getCellData(i, "che") == 1) {
                    k++;
                    if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "55" || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "70"
                        || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "82" || ds_retrieve.getCellData(i, "crryinoutPatternCd") == "90") {
                        if (ds_retrieve.getCellData(i, "crryinoutBasisNo") != "") {
                            await $c.win.alert("현재 선택하신 반출유형은 반출근거번호가 필요없습니다.삭제해 주시길 바랍니다.");
                            gr_retrieve.setFocusedCell(i, "crryinoutBasisNo", true);
                            return;
                        }
                    } else {
                        if (ds_retrieve.getCellData(i, "crryinoutPatternCd") == "") {
                            await $c.win.alert("반출유형코드는 필수항목입니다");
                            gr_retrieve.setFocusedCell(i, "crryinoutPatternCd", true);
                            return;
                        }
                    }

                    sndClsCd = ds_retrieve.getCellData(i, "sndClsCd");//"3";//

                    ds_retrieve.setCellData(i, "sndClsCd", sndClsCd);
                }

            } else if (ds_retrieve.getRowStatusValue(i) == 3) { //삭제
                if (ds_retrieve.getCellData(i, "che") == 1) k++;
            }
        }

        if (k == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["항목"]);
            return;
        }

        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// 조회 조건 초기화
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects([ed_wrkPlCd, ed_wrkPlNm, ed_mrn, ed_msn, ed_hsn, ed_blNo, ed_odrNo]);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);
    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

//-------------------------------------------------------------------------
// 작업장 POP UP
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 작업장 팝업
    udc_comCode.cfCommonPopUp((rtnList) => $c.gus.cfSetReturnValue(rtnList, ed_wrkPlCd, ed_wrkPlNm)
        , pCode
        , pName
        , pClose
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , null
        , pAllSearch
        , "작업장,작업장코드,작업장명"
    );
};

//-------------------------------------------------------------------------
// 반출근거번호 팝업창 호출 
//--------------------------------------------------------------------
scwin.f_BasisNoPopup = async function (row) {
    let data = {
        param1: 1 // 작업구분 : 컨테이너 
        , param2: ds_retrieve.getCellData(row, "wrkPlCd")
        , param3: ds_retrieve.getCellData(row, "wrkPlNm")
        , param4: ds_retrieve.getCellData(row, "mrn")
        , param5: ds_retrieve.getCellData(row, "msn")
        , param6: ds_retrieve.getCellData(row, "hsn")
    };

    let opts = {
        id: "smpPop",
        popupName: "반출승인내역조회",
        modal: false,
        type: "browserPopup",
        width: 1100,
        height: 400,
    };

    ds_retrieve.setCellData(row, "crryinoutBasisNo", ""); // 반출근거번호
    ds_retrieve.setCellData(row, "crryinoutCnt", "0");     // 반출개수
    ds_retrieve.setCellData(row, "crryinoutWt", "0");      // 반출중량
    let rtnValues = await $c.win.openPopup("/ui/ds/op/wrkrslts/yardwrkrslts/op_302_01_28p.xml", opts, data);
    if (rtnValues != null) {
        ds_retrieve.setCellData(row, "crryinoutBasisNo", rtnValues[0]); // 반출근거번호
        ds_retrieve.setCellData(row, "crryinoutCnt", rtnValues[6]);     // 반출개수
        ds_retrieve.setCellData(row, "crryinoutWt", rtnValues[7]);      // 반출중량
    }
};

//-------------------------------------------------------------------------
