    // viewerParam.add("viewer.zoom", "100");

    // $c.gus.cfOZReport("chb_printCheck", "chb_previewCheck", "/ds/op/wrkrslts/yardwrkrslts/op_302_01_16r.ozr", odiParam, viewerParam, formParam);

    let chkwrkplcd = ed_wrkPlCd.getValue();
    if ($c.gus.cfIsNull(chkwrkplcd)) {
        await $c.win.alert("작업장 코드는 필수 입력 항목입니다.");
        ed_wrkPlCd.focus();
        return;
    }

    if (chb_previewCheck.getValue() == "1" && chb_printCheck.getValue() == "1") {
        await $c.win.alert("미리보기 와 바로저장을 동시에 체크할 수 없습니다.");
        chb_printCheck.checkAll(false);
        return false;
    }

    let chkBtn = this.getUserData("userData1");
    let reportFile = "";
    let odiName = "";

    if ("b1" == chkBtn) {//세관재고(구)
        reportFile = "/ds/op/wrkrslts/yardwrkrslts/op_302_01_16r.ozr";
        odiName = "op_302_01_16r";
    } else if ("b2" == chkBtn) {//세관재고(신)
        reportFile = "/ds/op/wrkrslts/yardwrkrslts/op_302_01_16n.ozr";
        odiName = "op_302_01_16n";
    } else if ("b3" == chkBtn) {//세관재고(내국)
        reportFile = "/ds/op/wrkrslts/yardwrkrslts/op_302_01_16d.ozr";
        odiName = "op_302_01_16d";
    }

    let mode = "";
    let odiParam = {
        "wrkPlCd": ed_wrkPlCd.getValue(),
        "fromDt": crryinoutDtmFrom.getValue(),
        "toDt": crryinoutDtmTo.getValue()
    }

    if (chb_previewCheck.getValue() == "1") { mode = "preview"; }
    else if (chb_printCheck.getValue() == "1") { mode = "print"; }

    let data = {
        odiName: odiName,
        reportName: reportFile,
        odiParam: odiParam,
        viewerParam: {
            //"useprogressbar": true, // 프로그레스바 쓸지 말지
            "mode": mode,
            "zoom": "100"
        },
        formParam: {
        }
    };

    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: false,
        type: "browserPopup",
        width: 1000,
        height: 830,
        title: "오즈 리포트"
    };

    $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

