//-------------------------------------------------------------------------
// 오류 상세내역 조회 팝업
//-------------------------------------------------------------------------
scwin.f_errorPopUp = async function (row) {
    let docCd = "6NB";
    let declarNo = ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "crryinoutDeclarNo");
    let deg = 0;

    let data = {
        deg: deg			// 화면에서의 ??? Code Element의	Value
        , docCd: docCd					// 화면에서의 ??? Name Element의	Value
        , declarNo: declarNo					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
    };

    let opts = {
        id: "Pop",
        popupName: "오류상세내역",
        modal: true,
        type: "browserPopup",
        width: 860,      // 가로 크기 (픽셀)
        height: 580,     // 세로 크기 (픽셀)
        title: "Win pop"
    };

    await $c.win.openPopup("/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml", opts, data);
};

//삭제
scwin.f_Del = async function () {
    let cnt = 0;
    if (ds_retrieve.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, ["Data"]);
        return;
    }

    for (i = 0; i < ds_retrieve.getRowCount(); i++) {
        if (ds_retrieve.getRowStatusValue(i) == 1) { //갱신
            if (ds_retrieve.getCellData(i, "che") == 1) {
                cnt++;
            }
        }
    }

    if (cnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["항목"]);
        return;
    }

    if (await $c.win.confirm("정말삭제하시겠습니까?")) {
        $c.sbm.execute(sbm_saveDel);
    }
};

