scwin.gr_retrieve_onviewchange = function (info) {
    let colId = gr_retrieve.getColumnID(info.colIndex);
    let pName = ds_retrieve.getCellData(info.rowIndex, colId);
    let pOrgName = info.oldValue;
    switch (colId) {
        case "crryinoutBasisNo":
            if (pName != "" && pName != pOrgName) {
                scwin.f_BasisNoPopup(rowIndex);
            }
            break;

        default:
            break;
    }
};

