//선조회 체크
scwin.preRetrieve_onchange = function (info) {
    if (info.newValue == "1") {
        ed_odrNo.setDisabled(true);
        ed_odrNo.setValue("");
        ed_mrn.setMandatory(true);
        ed_mrn.setUserData("validExp", "화물관리번호:yes");
        txt_mrn.addClass("req");
    } else {
        ed_odrNo.setDisabled(false);
        ed_mrn.setMandatory(false);
        ed_mrn.setUserData("validExp", "");
        txt_mrn.removeClass("req");
    }
};

scwin.gr_retrieve_onafteredit = function (rowIndex, columnIndex, value) {
    const colID = gr_retrieve.getColumnID(columnIndex);
    const targetCols = ["crryinoutCnt", "crryinoutWt", "stockQty", "stockWt"];

    if (targetCols.includes(colID) && ($c.util.isEmpty(value) || isNaN(value))) {
        ds_retrieve.setCellData(rowIndex, colID, "0");
    }
};
